<script>
(function () {
  'use strict';

  // ---------- Math helpers ----------
  function clamp(v, a, b) { return Math.max(a, Math.min(b, v)); }
  function lerp(a, b, t) { return a + (b - a) * t; }
  function smooth(t) { return t * t * (3 - 2 * t); }

  function rotX(p, a) {
    var c = Math.cos(a), s = Math.sin(a);
    return { x: p.x, y: p.y * c - p.z * s, z: p.y * s + p.z * c };
  }
  function rotY(p, a) {
    var c = Math.cos(a), s = Math.sin(a);
    return { x: p.x * c + p.z * s, y: p.y, z: -p.x * s + p.z * c };
  }
  function rotZ(p, a) {
    var c = Math.cos(a), s = Math.sin(a);
    return { x: p.x * c - p.y * s, y: p.x * s + p.y * c, z: p.z };
  }
  function applyRot(p, ax, ay) {
    return rotY(rotX(p, ax), ay);
  }

  // ---------- Metal palettes ----------
  var METALS = {
    bronze: {
      base: [180, 110, 45],
      dark: [90, 50, 20],
      light: [230, 175, 100],
      spec: [255, 230, 180],
      rim: [140, 85, 35]
    },
    silver: {
      base: [175, 180, 190],
      dark: [70, 75, 85],
      light: [235, 238, 245],
      spec: [255, 255, 255],
      rim: [130, 135, 145]
    },
    gold: {
      base: [210, 165, 40],
      dark: [110, 75, 10],
      light: [255, 225, 120],
      spec: [255, 250, 220],
      rim: [170, 125, 25]
    },
    black: {
      base: [35, 30, 48],
      dark: [12, 10, 18],
      light: [90, 80, 120],
      spec: [200, 190, 255],
      rim: [25, 22, 38]
    }
  };

  function rgb(c, a) {
    if (a === undefined || a >= 1) return 'rgb(' + (c[0]|0) + ',' + (c[1]|0) + ',' + (c[2]|0) + ')';
    return 'rgba(' + (c[0]|0) + ',' + (c[1]|0) + ',' + (c[2]|0) + ',' + a + ')';
  }
  function mix(a, b, t) {
    return [lerp(a[0], b[0], t), lerp(a[1], b[1], t), lerp(a[2], b[2], t)];
  }
  function shade(c, k) {
    return [clamp(c[0] * k, 0, 255), clamp(c[1] * k, 0, 255), clamp(c[2] * k, 0, 255)];
  }

  // ---------- Coin renderer ----------
  function createCoinRenderer(canvas, options) {
    var ctx = canvas.getContext('2d');
    var W = canvas.width;
    var H = canvas.height;
    var metalKey = (options && options.metal) || 'gold';
    var denom = (options && options.denom) || '10,000';
    var showEmblemDetail = options && options.detail !== false;

    // Light direction (world space, fixed)
    var Lx = -0.45, Ly = -0.55, Lz = 0.7;
    var llen = Math.sqrt(Lx * Lx + Ly * Ly + Lz * Lz);
    Lx /= llen; Ly /= llen; Lz /= llen;

    function project(p, scale, cx, cy, persp) {
      var d = 1 / (1 + p.z * persp);
      return { x: cx + p.x * scale * d, y: cy - p.y * scale * d, z: p.z, d: d };
    }

    function faceNormal(ax, ay) {
      // Front face normal is +Z before rotation
      var n = applyRot({ x: 0, y: 0, z: 1 }, ax, ay);
      return n;
    }

    function drawReededEdge(ax, ay, R, T, scale, cx, cy, persp, metal, segs) {
      var half = T * 0.5;
      var ptsOuter = [];
      var ptsInner = [];
      var i, th, ridge, rr, p0, p1, q0, q1, n;

      for (i = 0; i <= segs; i++) {
        th = (i / segs) * Math.PI * 2;
        // Reeded: radial ridges
        ridge = 1 + 0.018 * Math.sin(th * 72);
        rr = R * ridge;
        p0 = applyRot({ x: rr * Math.cos(th), y: rr * Math.sin(th), z: half }, ax, ay);
        p1 = applyRot({ x: rr * Math.cos(th), y: rr * Math.sin(th), z: -half }, ax, ay);
        q0 = project(p0, scale, cx, cy, persp);
        q1 = project(p1, scale, cx, cy, persp);
        // outward normal approx in world after rot
        n = applyRot({ x: Math.cos(th), y: Math.sin(th), z: 0 }, ax, ay);
        ptsOuter.push({ q0: q0, q1: q1, n: n, th: th, ridge: ridge, i: i });
      }

      // Draw edge quads back-to-front by average z
      var quads = [];
      for (i = 0; i < segs; i++) {
        var a = ptsOuter[i];
        var b = ptsOuter[i + 1];
        var zAvg = (a.q0.z + a.q1.z + b.q0.z + b.q1.z) * 0.25;
        quads.push({ a: a, b: b, z: zAvg });
      }
      quads.sort(function (u, v) { return u.z - v.z; });

      for (i = 0; i < quads.length; i++) {
        var qa = quads[i].a, qb = quads[i].b;
        var nx = (qa.n.x + qb.n.x) * 0.5;
        var ny = (qa.n.y + qb.n.y) * 0.5;
        var nz = (qa.n.z + qb.n.z) * 0.5;
        var nd = Math.sqrt(nx * nx + ny * ny + nz * nz) || 1;
        nx /= nd; ny /= nd; nz /= nd;
        var ndot = nx * Lx + ny * Ly + nz * Lz;
        var lit = clamp(0.22 + ndot * 0.78, 0.08, 1.15);
        // ridge alternation
        var ridgeLit = 0.85 + 0.25 * Math.sin(qa.th * 72);
        lit *= ridgeLit;
        var col = mix(metal.dark, metal.light, clamp(lit, 0, 1));
        // specular on edge
        var hx = Lx, hy = Ly, hz = Lz + 1;
        var hl = Math.sqrt(hx * hx + hy * hy + hz * hz);
        hx /= hl; hy /= hl; hz /= hl;
        var spec = Math.pow(clamp(nx * hx + ny * hy + nz * hz, 0, 1), 28);
        col = mix(col, metal.spec, spec * 0.85);

        ctx.beginPath();
        ctx.moveTo(qa.q0.x, qa.q0.y);
        ctx.lineTo(qb.q0.x, qb.q0.y);
        ctx.lineTo(qb.q1.x, qb.q1.y);
        ctx.lineTo(qa.q1.x, qa.q1.y);
        ctx.closePath();
        ctx.fillStyle = rgb(col);
        ctx.fill();
      }
    }

    function ellipsePath(cx, cy, rx, ry, rot) {
      ctx.beginPath();
      ctx.ellipse(cx, cy, Math.abs(rx), Math.abs(ry), rot, 0, Math.PI * 2);
    }

    function drawFaceDisc(ax, ay, R, zOff, scale, cx, cy, persp, metal, isFront) {
      var n = faceNormal(ax, ay);
      // If drawing front face geometry at +z, visibility when n.z > 0 for front
      // We still draw the disc; caller decides order
      var segs = 96;
      var halfPts = [];
      var i, th, p, q;
      for (i = 0; i <= segs; i++) {
        th = (i / segs) * Math.PI * 2;
        p = applyRot({ x: R * Math.cos(th), y: R * Math.sin(th), z: zOff }, ax, ay);
        q = project(p, scale, cx, cy, persp);
        halfPts.push(q);
      }
      // center
      var pc = applyRot({ x: 0, y: 0, z: zOff }, ax, ay);
      var qc = project(pc, scale, cx, cy, persp);

      // Build path
      ctx.beginPath();
      ctx.moveTo(halfPts[0].x, halfPts[0].y);
      for (i = 1; i < halfPts.length; i++) ctx.lineTo(halfPts[i].x, halfPts[i].y);
      ctx.closePath();

      // Base metallic radial-ish fill via lighting on face normal
      var ndot = n.x * Lx + n.y * Ly + n.z * Lz;
      var baseLit = clamp(0.35 + ndot * 0.55, 0.15, 1.0);
      var baseCol = mix(metal.dark, metal.base, baseLit);

      // Gradient across face for metal sheen (rakes with rotation)
      // Use light projected onto face plane
      var gdx = Lx - n.x * ndot;
      var gdy = Ly - n.y * ndot;
      var gdz = Lz - n.z * ndot;
      // Transform a face-local axis to screen for gradient direction
      var right = applyRot({ x: 1, y: 0, z: 0 }, ax, ay);
      var up = applyRot({ x: 0, y: 1, z: 0 }, ax, ay);
      var gx = right.x * gdx + right.y * gdy + right.z * gdz;
      var gy = up.x * gdx + up.y * gdy + up.z * gdz;

      var gradLen = R * scale * 0.95 * qc.d;
      var gcx = qc.x;
      var gcy = qc.y;
      // Offset gradient center toward light for specular rake
      var hx = Lx, hy = Ly, hz = Lz + 1.0;
      var hl = Math.sqrt(hx * hx + hy * hy + hz * hz);
      hx /= hl; hy /= hl; hz /= hl;
      var specN = clamp(n.x * hx + n.y * hy + n.z * hz, 0, 1);
      var specPow = Math.pow(specN, 12);

      // Specular hotspot position on face (reflect light over normal, project)
      var rx = 2 * ndot * n.x - Lx;
      var ry = 2 * ndot * n.y - Ly;
      var rz = 2 * ndot * n.z - Lz;
      // Intersection of reflection with face for highlight offset in face coords
      // Use opposite of light projected
      var hlx = -(Lx - n.x * ndot);
      var hly = -(Ly - n.y * ndot);
      var faceHx = right.x * hlx + right.y * hly + right.z * (-(Lz - n.z * ndot));
      var faceHy = up.x * hlx + up.y * hly + up.z * (-(Lz - n.z * ndot));
      var fhl = Math.sqrt(faceHx * faceHx + faceHy * faceHy) || 1;
      faceHx /= fhl; faceHy /= fhl;
      var hotDist = R * 0.42 * (1 - specN * 0.3);
      var hotLocal = applyRot({ x: faceHx * hotDist, y: faceHy * hotDist, z: zOff }, ax, ay);
      var hot = project(hotLocal, scale, cx, cy, persp);

      var grd = ctx.createRadialGradient(hot.x, hot.y, 0, gcx, gcy, gradLen);
      var hi = mix(baseCol, metal.light, 0.55 + specPow * 0.35);
      var mid = baseCol;
      var lo = mix(baseCol, metal.dark, 0.55);
      grd.addColorStop(0, rgb(mix(hi, metal.spec, specPow * 0.75)));
      grd.addColorStop(0.18, rgb(hi));
      grd.addColorStop(0.45, rgb(mid));
      grd.addColorStop(0.78, rgb(lo));
      grd.addColorStop(1, rgb(mix(lo, metal.dark, 0.4)));

      ctx.fillStyle = grd;
      ctx.fill();

      // Specular bloom ellipse
      if (specPow > 0.02) {
        ctx.save();
        ctx.beginPath();
        ctx.moveTo(halfPts[0].x, halfPts[0].y);
        for (i = 1; i < halfPts.length; i++) ctx.lineTo(halfPts[i].x, halfPts[i].y);
        ctx.closePath();
        ctx.clip();
        var bloom = ctx.createRadialGradient(hot.x, hot.y, 0, hot.x, hot.y, gradLen * 0.55);
        bloom.addColorStop(0, rgb(metal.spec, 0.55 * specPow + 0.15));
        bloom.addColorStop(0.35, rgb(metal.spec, 0.18 * specPow));
        bloom.addColorStop(1, rgb(metal.spec, 0));
        ctx.fillStyle = bloom;
        ctx.fillRect(0, 0, W, H);
        ctx.restore();
      }

      // Rim ring (raised)
      drawRaisedRing(ax, ay, R * 0.96, R * 0.88, zOff, scale, cx, cy, persp, metal, n, 0.15);

      // Inner content
      if (isFront) {
        drawFrontEmblem(ax, ay, R, zOff, scale, cx, cy, persp, metal, n, qc);
      } else {
        drawBackDenom(ax, ay, R, zOff, scale, cx, cy, persp, metal, n, qc, denom);
      }

      // Outer thin dark edge line for definition
      ctx.beginPath();
      ctx.moveTo(halfPts[0].x, halfPts[0].y);
      for (i = 1; i < halfPts.length; i++) ctx.lineTo(halfPts[i].x, halfPts[i].y);
      ctx.closePath();
      ctx.strokeStyle = rgb(shade(metal.dark, 0.7), 0.55);
      ctx.lineWidth = 1.2;
      ctx.stroke();

      return { qc: qc, n: n, halfPts: halfPts, hot: hot, specPow: specPow };
    }

    function faceBasis(ax, ay) {
      var o = applyRot({ x: 0, y: 0, z: 0 }, ax, ay);
      var r = applyRot({ x: 1, y: 0, z: 0 }, ax, ay);
      var u = applyRot({ x: 0, y: 1, z: 0 }, ax, ay);
      return { o: o, r: r, u: u };
    }

    function facePoint(ax, ay, lx, ly, zOff, scale, cx, cy, persp) {
      var p = applyRot({ x: lx, y: ly, z: zOff }, ax, ay);
      return project(p, scale, cx, cy, persp);
    }

    function drawRaisedRing(ax, ay, R0, R1, zOff, scale, cx, cy, persp, metal, n, raise) {
      var segs = 80;
      var outer = [], inner = [];
      var i, th;
      for (i = 0; i <= segs; i++) {
        th = (i / segs) * Math.PI * 2;
        outer.push(facePoint(ax, ay, R0 * Math.cos(th), R0 * Math.sin(th), zOff, scale, cx, cy, persp));
        inner.push(facePoint(ax, ay, R1 * Math.cos(th), R1 * Math.sin(th), zOff, scale, cx, cy, persp));
      }
      ctx.beginPath();
      ctx.moveTo(outer[0].x, outer[0].y);
      for (i = 1; i < outer.length; i++) ctx.lineTo(outer[i].x, outer[i].y);
      for (i = inner.length - 1; i >= 0; i--) ctx.lineTo(inner[i].x, inner[i].y);
      ctx.closePath();

      var ndot = n.x * Lx + n.y * Ly + n.z * Lz;
      // Fake bevel: lighter toward light side of ring
      var col = mix(metal.dark, metal.light, clamp(0.4 + ndot * 0.4 + raise, 0, 1));
      ctx.fillStyle = rgb(col, 0.92);
      ctx.fill();

      // Highlight stroke on light side
      ctx.beginPath();
      for (i = 0; i <= segs; i++) {
        th = (i / segs) * Math.PI * 2;
        var lx = Math.cos(th), ly = Math.sin(th);
        // light-facing on face
        var faceL = (-Lx * n.z + /*approx*/ 0);
        var side = lx * (-(Lx - n.x * ndot)) + ly * (-(Ly - n.y * ndot));
        var pt = outer[i];
        if (i === 0) ctx.moveTo(pt.x, pt.y);
        else ctx.lineTo(pt.x, pt.y);
      }
      ctx.strokeStyle = rgb(metal.light, 0.35);
      ctx.lineWidth = 1;
      ctx.stroke();
    }

    function embossPath(pathFn, ax, ay, zOff, scale, cx, cy, persp, metal, n, width) {
      // Draw embossed stroke: dark offset + light offset + fill
      ctx.save();
      var ndot = n.x * Lx + n.y * Ly + n.z * Lz;
      // Screen-space light direction for emboss offset
      var right = applyRot({ x: 1, y: 0, z: 0 }, ax, ay);
      var up = applyRot({ x: 0, y: 1, z: 0 }, ax, ay);
      var lx = right.x * Lx + right.y * Ly + right.z * Lz;
      var ly = up.x * Lx + up.y * Ly + up.z * Lz;
      var ll = Math.sqrt(lx * lx + ly * ly) || 1;
      lx /= ll; ly /= ll;
