      ctx.beginPath();
      pathFn(0);
      ctx.strokeStyle = rgb(mix(metal.base, metal.light, 0.35 + ndot * 0.25));
      ctx.lineWidth = width;
      ctx.stroke();

      // Highlight toward light
      ctx.beginPath();
      pathFn(0);
      ctx.strokeStyle = rgb(metal.light, 0.55);
      ctx.lineWidth = Math.max(1, width * 0.35);
      ctx.stroke();

      ctx.restore();
    }

    function drawFrontEmblem(ax, ay, R, zOff, scale, cx, cy, persp, metal, n, qc) {
      var s = R;
      function fp(lx, ly) {
        return facePoint(ax, ay, lx, ly, zOff, scale, cx, cy, persp);
      }

      // Inner circle field
      drawRaisedRing(ax, ay, R * 0.82, R * 0.78, zOff, scale, cx, cy, persp, metal, n, 0.1);

      // Central medallion disc
      var segs = 64, i, th, p;
      ctx.beginPath();
      for (i = 0; i <= segs; i++) {
        th = (i / segs) * Math.PI * 2;
