      ctx.closePath();
      var ndot = n.x * Lx + n.y * Ly + n.z * Lz;
      ctx.fillStyle = rgb(mix(metal.dark, metal.base, 0.45 + ndot * 0.25), 0.9);
      ctx.fill();

      // Stylized "W" monogram (raised)
      embossPath(function () {
        var pts = [
          [-0.28, 0.22], [-0.18, -0.22], [-0.08, 0.08],
          [0.0, -0.22], [0.08, 0.08], [0.18, -0.22], [0.28, 0.22]
        ];
        var j, q;
        for (j = 0; j < pts.length; j++) {
          q = fp(pts[j][0] * s * 0.85, pts[j][1] * s * 0.85);
          if (j === 0) ctx.moveTo(q.x, q.y); else ctx.lineTo(q.x, q.y);
        }
      }, ax, ay, zOff, scale, cx, cy, persp, metal, n, 3.2 * (scale / 160));

      // Crossed bars behind W (token motif)
      embossPath(function () {
        var a = fp(-0.32 * s, -0.12 * s), b = fp(0.32 * s, 0.12 * s);
        ctx.moveTo(a.x, a.y); ctx.lineTo(b.x, b.y);
      }, ax, ay, zOff, scale, cx, cy, persp, metal, n, 1.6 * (scale / 160));
      embossPath(function () {
        var a = fp(-0.32 * s, 0.12 * s), b = fp(0.32 * s, -0.12 * s);
        ctx.moveTo(a.x, a.y); ctx.lineTo(b.x, b.y);
      }, ax, ay, zOff, scale, cx, cy, persp, metal, n, 1.6 * (scale / 160));

      // Stars at compass points
      function star(cxL, cyL, rad) {
        embossPath(function () {
          var k, ang, rr, q, first = true;
          for (k = 0; k < 10; k++) {
            ang = -Math.PI / 2 + k * Math.PI / 5;
            rr = (k % 2 === 0) ? rad : rad * 0.4;
            q = fp(cxL + Math.cos(ang) * rr, cyL + Math.sin(ang) * rr);
            if (first) { ctx.moveTo(q.x, q.y); first = false; }
            else ctx.lineTo(q.x, q.y);
          }
          ctx.closePath();
        }, ax, ay, zOff, scale, cx, cy, persp, metal, n, 1.2 * (scale / 160));
      }
      star(0, R * 0.62, R * 0.06);
      star(0, -R * 0.62, R * 0.06);
      star(R * 0.62, 0, R * 0.05);
      star(-R * 0.62, 0, R * 0.05);

      // Arc text "WASTED TOKEN" / "MINT" via small embossed ticks forming letters is hard;
      // draw letterforms as short embossed polylines along arcs
      if (showEmblemDetail) {
        drawArcText(ax, ay, R * 0.68, zOff, scale, cx, cy, persp, metal, n, 'WASTED TOKEN', -Math.PI * 0.72, Math.PI * 0.72, false);
        drawArcText(ax, ay, R * 0.68, zOff, scale, cx, cy, persp, metal, n, 'MINT', Math.PI * 0.78, Math.PI * 1.22, true);
      }

      // Center dot
      var c = fp(0, 0);
      ctx.beginPath();
      ctx.arc(c.x, c.y, 2.2 * (scale / 160), 0, Math.PI * 2);
      ctx.fillStyle = rgb(metal.light, 0.85);
      ctx.fill();
    }

    function drawArcText(ax, ay, rad, zOff, scale, cx, cy, persp, metal, n, text, a0, a1, flip) {
      var chars = text.split('');
      var i, t, ang, ch, p, tang;
      var count = chars.length;
      ctx.save();
      ctx.font = 'bold ' + Math.max(8, (11 * scale / 160)) + 'px Georgia, serif';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      var ndot = n.x * Lx + n.y * Ly + n.z * Lz;
      for (i = 0; i < count; i++) {
        ch = chars[i];
        if (ch === ' ') continue;
        t = count === 1 ? 0.5 : i / (count - 1);
        ang = lerp(a0, a1, t);
        p = facePoint(ax, ay, rad * Math.cos(ang), rad * Math.sin(ang), zOff, scale, cx, cy, persp);
