    }

    function drawBackDenom(ax, ay, R, zOff, scale, cx, cy, persp, metal, n, qc, denomStr) {
      var s = R;
      function fp(lx, ly) {
        return facePoint(ax, ay, lx, ly, zOff, scale, cx, cy, persp);
      }

      drawRaisedRing(ax, ay, R * 0.82, R * 0.78, zOff, scale, cx, cy, persp, metal, n, 0.1);

      // Decorative laurel-like arcs
      embossPath(function () {
        var k, a, q, first = true;
        for (k = 0; k <= 20; k++) {
          a = -Math.PI * 0.55 + (k / 20) * Math.PI * 0.5;
