      }, ax, ay, zOff, scale, cx, cy, persp, metal, n, 1.5 * (scale / 160));
      embossPath(function () {
        var k, a, q, first = true;
        for (k = 0; k <= 20; k++) {
          a = Math.PI * 0.05 + (k / 20) * Math.PI * 0.5;
