      }, ax, ay, zOff, scale, cx, cy, persp, metal, n, 1.5 * (scale / 160));

      // Large denomination — draw as embossed block text using face basis projection
      // Because canvas text doesn't warp to 3D plane easily, we draw each character
      // positioned on the face plane with approximate shear via neighboring points.
      drawPlaneText(ax, ay, zOff, scale, cx, cy, persp, metal, n, denomStr, 0, 0.06 * s, 0.22 * s, true);
      drawPlaneText(ax, ay, zOff, scale, cx, cy, persp, metal, n, 'TOKENS', 0, -0.22 * s, 0.11 * s, false);

      // Small serial ring text
      if (showEmblemDetail) {
