      }

      // Center horizontal rules
      embossPath(function () {
        var a = fp(-0.35 * s, 0.28 * s), b = fp(0.35 * s, 0.28 * s);
        ctx.moveTo(a.x, a.y); ctx.lineTo(b.x, b.y);
      }, ax, ay, zOff, scale, cx, cy, persp, metal, n, 1.2 * (scale / 160));
      embossPath(function () {
        var a = fp(-0.35 * s, -0.38 * s), b = fp(0.35 * s, -0.38 * s);
        ctx.moveTo(a.x, a.y); ctx.lineTo(b.x, b.y);
      }, ax, ay, zOff, scale, cx, cy, persp, metal, n, 1.2 * (scale / 160));
    }

    function drawPlaneText(ax, ay, zOff, scale, cx, cy, persp, metal, n, text, lx, ly, size, bold) {
      // Sample three points to get affine transform for the face
      var o = facePoint(ax, ay, lx, ly, zOff, scale, cx, cy, persp);
      var px = facePoint(ax, ay, lx + size, ly, zOff, scale, cx, cy, persp);
      var py = facePoint(ax, ay, lx, ly + size, zOff, scale, cx, cy, persp);
      var ex = px.x - o.x, ey = px.y - o.y;
      var fx = py.x - o.x, fy = py.y - o.y;
      // If face is edge-on, skip
      var area = ex * fy - ey * fx;
      if (Math.abs(area) < 4) return;

      ctx.save();
      ctx.font = (bold ? 'bold ' : '') + Math.max(10, size * 2.8) + 'px Georgia, serif';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';

      // Use setTransform to map unit text plane roughly onto face
      // Identity: text at origin; we want origin -> o, unit x -> (ex,ey) scaled by font metrics
      var fontSize = Math.max(10, size * 2.8);
      // measure width in local units: we want text width ~ 2.2 * size for long strings
      var metrics = ctx.measureText(text);
      var tw = metrics.width || fontSize * text.length * 0.55;
      var scaleX = (1.0) / fontSize; // we'll apply matrix differently

      // Build matrix: screen = o + (x/fontSize)*ex_adjusted + (y/fontSize)*fy
      // For text of width tw, we want it to span ~ 1.8*size in local x for long text
      var targetW = size * (text.length > 6 ? 3.6 : 2.4);
      var sx = targetW / tw;
      var sy = size * 1.1 / fontSize;

      // Transform: [ex*sx, fx*sy, ox; ey*sx, fy*sy, oy]
      ctx.setTransform(ex * sx, ey * sx, fx * sy, fy * sy, o.x, o.y);

      var ndot = n.x * Lx + n.y * Ly + n.z * Lz;
      ctx.fillStyle = rgb(metal.dark, 0.8);
      ctx.fillText(text, 0.6, 0.6);
      ctx.fillStyle = rgb(mix(metal.base, metal.light, 0.55 + ndot * 0.3));
      ctx.fillText(text, 0, 0);
      ctx.fillStyle = rgb(metal.light, 0.35);
      ctx.fillText(text, -0.4, -0.4);
      ctx.restore();
      // reset transform to identity for canvas pixel space
      ctx.setTransform(1, 0, 0, 1, 0, 0);
    }

    function renderAt(t) {
      // Deterministic mapping t in [0,1]
      t = ((t % 1) + 1) % 1;
      var ax = t * Math.PI * 2;           // flip about horizontal (X)
      var ay = t * Math.PI * 2 * 1.0;     // spin about vertical (Y)
      // slight extra so motion feels rich but still 1-loop periodic
      ay = t * Math.PI * 2;

      var metal = METALS[metalKey] || METALS.gold;
      var cx = W * 0.5;
      var cy = H * 0.5;
      var R = 1.0;
      var T = 0.14;
      var scale = Math.min(W, H) * 0.36; // coin well inside canvas
      var persp = 0.28;

      // Backdrop — simple, clean
      ctx.setTransform(1, 0, 0, 1, 0, 0);
      ctx.clearRect(0, 0, W, H);
      var bg = ctx.createRadialGradient(cx, cy, 10, cx, cy, Math.min(W, H) * 0.5);
      bg.addColorStop(0, '#141824');
      bg.addColorStop(0.55, '#0c0e14');
      bg.addColorStop(1, '#08090d');
      ctx.fillStyle = bg;
      ctx.fillRect(0, 0, W, H);

      // Soft ground shadow
      var n = faceNormal(ax, ay);
      var shadowScaleX = 0.85 + 0.15 * Math.abs(n.z);
      var shadowScaleY = 0.28 + 0.12 * (1 - Math.abs(n.z));
      ctx.save();
      ctx.translate(cx, cy + scale * 0.95);
      ctx.scale(shadowScaleX, shadowScaleY);
      var sh = ctx.createRadialGradient(0, 0, 2, 0, 0, scale * 0.9);
      sh.addColorStop(0, 'rgba(0,0,0,0.45)');
      sh.addColorStop(1, 'rgba(0,0,0,0)');
      ctx.fillStyle = sh;
