      var frontVisible = n.z > 0;
      var zFront = T * 0.5;
      var zBack = -T * 0.5;

      // Draw far face first, then edge, then near face
      if (frontVisible) {
        // seeing front: draw back first (may peek at edges), edge, front
        if (Math.abs(n.z) < 0.98) {
          // back may be partially relevant only via edge; still draw back under
          drawFaceDisc(ax, ay, R, zBack, scale, cx, cy, persp, metal, false);
        }
        drawReededEdge(ax, ay, R, T, scale, cx, cy, persp, metal, 120);
        drawFaceDisc(ax, ay, R, zFront, scale, cx, cy, persp, metal, true);
      } else {
        drawFaceDisc(ax, ay, R, zFront, scale, cx, cy, persp, metal, true);
        drawReededEdge(ax, ay, R, T, scale, cx, cy, persp, metal, 120);
        drawFaceDisc(ax, ay, R, zBack, scale, cx, cy, persp, metal, false);
      }

      // When nearly edge-on, emphasize reeded silhouette
      if (Math.abs(n.z) < 0.25) {
        drawReededEdge(ax, ay, R, T, scale, cx, cy, persp, metal, 120);
      }
